const device = {
    identifiers: ["highland_landroid"],
    name: "Highland Landroid",
    model: "Landroid Vision WR344",
    manufacturer: "Worx"
};

const state_topic = "highland/state/landroid/rain_monitor";
const base = "homeassistant/sensor/highland_landroid";
const binary_base = "homeassistant/binary_sensor/highland_landroid";
const session_topic = "highland/state/landroid/session";
const conditions_topic = "highland/state/landroid/conditions";

const entities = [
    {
        config_topic: `${binary_base}/rain_delay_active/config`,
        config: {
            name: "Rain Delay Active",
            unique_id: "highland_landroid_rain_delay_active",
            object_id: "landroid_rain_delay_active",
            state_topic,
            value_template: "{{ value_json.delay_active }}",
            payload_on: true,
            payload_off: false,
            icon: "mdi:weather-rainy"
        }
    },
    {
        config_topic: `${binary_base}/conditions_delay_active/config`,
        config: {
            name: "Conditions Delay Active",
            unique_id: "highland_landroid_conditions_delay_active",
            object_id: "landroid_conditions_delay_active",
            state_topic: conditions_topic,
            value_template: "{{ value_json.conditions_delay_active }}",
            payload_on: true,
            payload_off: false,
            icon: "mdi:thermometer-alert"
        }
    },
    {
        config_topic: `${base}/conditions_status/config`,
        config: {
            name: "Conditions Status",
            unique_id: "highland_landroid_conditions_status",
            object_id: "landroid_conditions_status",
            state_topic: conditions_topic,
            value_template: "{{ value_json.conditions_status }}"
        }
    },
    {
        config_topic: `${base}/mowing_window/config`,
        config: {
            name: "Mowing Window",
            unique_id: "highland_landroid_mowing_window",
            object_id: "landroid_mowing_window",
            state_topic: session_topic,
            value_template: "{{ value_json.mowing_window }}"
        }
    },
    {
        config_topic: `${base}/rain_monitor_state/config`,
        config: {
            name: "Rain Monitor State",
            unique_id: "highland_landroid_rain_monitor_state",
            object_id: "landroid_rain_monitor_state",
            state_topic,
            value_template: "{{ value_json.rain_monitor_state }}"
        }
    },
    {
        config_topic: `${base}/event_accumulation/config`,
        config: {
            name: "Rain Event Accumulation",
            unique_id: "highland_landroid_event_accumulation",
            object_id: "landroid_rain_event_accumulation",
            state_topic,
            value_template: "{{ value_json.event_accumulation_inches }}",
            unit_of_measurement: "in",
            device_class: "precipitation",
            state_class: "measurement"
        }
    },
    {
        config_topic: `${base}/rain_tier/config`,
        config: {
            name: "Rain Tier",
            unique_id: "highland_landroid_rain_tier",
            object_id: "landroid_rain_tier",
            state_topic,
            value_template: "{{ value_json.rain_tier }}"
        }
    },
    {
        config_topic: `${base}/cooldown_end_time/config`,
        config: {
            name: "Cooldown End Time",
            unique_id: "highland_landroid_cooldown_end_time",
            object_id: "landroid_cooldown_end_time",
            state_topic,
            value_template: "{{ value_json.cooldown_end_time }}",
            device_class: "timestamp"
        }
    },
    {
        config_topic: `${binary_base}/battery_charge_state/config`,
        config: {
            name: "Battery Charge State",
            unique_id: "highland_landroid_battery_charge_state",
            object_id: "landroid_battery_charge_state",
            state_topic: "highland/state/landroid/battery_charge_state",
            device_class: "battery_charging",
            payload_on: "Charging",
            payload_off: "Discharging"
        }
    }
];

for (const e of entities) {
    node.send({
        topic: e.config_topic,
        payload: JSON.stringify({ ...e.config, device }),
        retain: true
    });
}

return null;

const config = global.get('config').landroid;

const { precipitation_type, rain_accumulated } = msg.payload;
const precip_active = precipitation_type !== 'None'; 

if (msg.payload.temperature !== undefined) {
    flow.set('latest_observation', {
        temperature: msg.payload.temperature,
        humidity: msg.payload.humidity,
        solar_radiation: msg.payload.solar_radiation,
        timestamp: msg.payload.timestamp
    });
}

msg.payload = {
    source: 'observation',
    precip_active,
    intensity: rain_accumulated,
    type: precipitation_type
};

return msg;

msg.payload = {
    source: 'evt_precip',
    precip_active: true,
    intensity: null,
    type: 'Rain'
};

return msg;

const config = global.get('config').landroid;

// Read current state from context
let rm = flow.get('rain_monitor') || {
    state: 'DRY',
    event_accumulation: 0,
    cooldown_end_time: null,
    last_rain_end: null
};

const { source, precip_active, intensity } = msg.payload;

node.status({ fill: 'grey', shape: 'dot', text: `${rm.state} | acc: ${rm.event_accumulation.toFixed(4)}` });

if (source === 'startup') {
    msg.payload = rm;
    return msg;
}

if (source === 'cooldown_check') {
    if (rm.state !== 'COOLDOWN') {
        return null;
    }

    const now = Date.now();
    const cooldown_end = new Date(rm.cooldown_end_time).getTime();

    if (now < cooldown_end) {
        return null; // still waiting
    }

    // Cooldown elapsed — check NWS forecast
    const minutely = global.get('weather_canonical')?.minutely || [];
    const config = global.get('config').landroid;
    const floorPerHr = config.rain_suppression.precipitation_floor_in_per_min * 60;
    const clearMinutes = config.rain_suppression.forecast_clear_minutes;

    const threat = minutely.slice(0, clearMinutes).some(m =>
        (m.precip_probability >= 0.60) && (m.precip_intensity >= floorPerHr)
    );

    if (threat) {
        // Extend cooldown
        rm.cooldown_end_time = new Date(now + clearMinutes * 60 * 1000).toISOString();
        flow.set('rain_monitor', rm, 'default');
        msg.payload = rm;
        return msg;
    }

    // Clear to mow
    rm.state = 'DRY';
    rm.cooldown_end_time = null;
    flow.set('rain_monitor', rm, 'default');
    msg.payload = rm;
    return msg;
}

// --- Precipitation observation ---
const prev_state = rm.state;

if (rm.state === 'DRY') {
    if (precip_active) {
        rm.state = 'RAINING';
        rm.event_accumulation = intensity || 0;  // capture first observation
    } else {
        return null;
    }
}
else if (rm.state === 'RAINING') {
    if (precip_active) {
        if (intensity !== null) {
            rm.event_accumulation += intensity;
        }
        // Only emit if accumulation changed meaningfully
        if (Math.abs(rm.event_accumulation - (flow.get('rain_monitor')?.event_accumulation || 0)) < 0.005) {
            flow.set('rain_monitor', rm);
            return null;
        }
    } else {
        // Rain stopped — transition to COOLDOWN
        rm.state = 'COOLDOWN';
        rm.last_rain_end = new Date().toISOString();

        // Tier lookup
        const tiers = config.rain_accumulation_tiers;
        const acc = rm.event_accumulation;
        let cooldown_minutes = 30; // fallback
        let skip_day = false;

        for (const tier of tiers) {
            if (tier.max_inches === null || acc <= tier.max_inches) {
                if (tier.skip_day) {
                    skip_day = true;
                } else {
                    cooldown_minutes = tier.cooldown_minutes;
                }
                break;
            }
        }

        if (skip_day) {
            // Set cooldown_end_time to tomorrow at schedule_start
            const [h, m] = config.schedule.earliest_start.split(':').map(Number);
            const tomorrow = new Date();
            tomorrow.setDate(tomorrow.getDate() + 1);
            tomorrow.setHours(h, m, 0, 0);
            rm.cooldown_end_time = tomorrow.toISOString();
        } else {
            rm.cooldown_end_time = new Date(Date.now() + cooldown_minutes * 60 * 1000).toISOString();
        }
    }
}
else if (rm.state === 'COOLDOWN') {
    if (precip_active) {
        // Rain returned during cooldown
        rm.state = 'RAINING';
        rm.cooldown_end_time = null;
        rm.event_accumulation += (intensity || 0);
    } else {
        return null; // still in cooldown, poller handles transition
    }
}

// Persist state
flow.set('rain_monitor', rm);

// Only emit if state changed or accumulation updated
msg.payload = rm;
return msg;

const { state, event_accumulation, cooldown_end_time, last_rain_end } = msg.payload;

// Derive tier label from accumulation
const tiers = global.get('config').landroid.rain_accumulation_tiers;

let tier_label = 'Inactive';

if (state !== 'DRY') {
    for (const tier of tiers) {
        if (tier.max_inches === null || event_accumulation <= tier.max_inches) {
            if (tier.skip_day) {
                tier_label = 'Significant';
            } else if (tier.max_inches <= 0.05) {
                tier_label = 'Trace';
            } else if (tier.max_inches <= 0.15) {
                tier_label = 'Light';
            } else if (tier.max_inches <= 0.50) {
                tier_label = 'Moderate';
            } else {
                tier_label = 'Heavy';
            }
            break;
        }
    }
}

const mow_ready = state === 'DRY';

// Set flow context inline
flow.set('mow_ready', mow_ready);
flow.set('landroid_cooldown_end_time', cooldown_end_time);

// Detect mow_ready transition for rain signal to Session Manager
const prev_mow_ready = flow.get('rain_monitor_prev_mow_ready');
flow.set('rain_monitor_prev_mow_ready', mow_ready);
const rain_signal = (prev_mow_ready === true && mow_ready === false)
    ? { payload: { type: 'rain' } }
    : null;

const mqtt_msg = {
    topic: 'highland/state/landroid/rain_monitor',
    payload: JSON.stringify({
        delay_active: !mow_ready,
        rain_monitor_state: state,
        event_accumulation_inches: state === 'DRY' ? 0 : Math.round(event_accumulation * 10000) / 10000,
        rain_tier: tier_label,
        cooldown_end_time: cooldown_end_time,
        last_rain_end: last_rain_end,
        mow_ready
    }),
    retain: true
};

return [mqtt_msg, rain_signal];

const rm = flow.get('rain_monitor', 'default') || {};

if (rm.state !== 'COOLDOWN') {
    return null;
}

msg.payload = {
    source: 'cooldown_check'
};

return msg;

let rm = flow.get('rain_monitor', 'default');

// First run — no stored state
if (!rm) {
    rm = {
        state: 'DRY',
        event_accumulation: 0,
        cooldown_end_time: null,
        last_rain_end: null
    };
    flow.set('rain_monitor', rm, 'default');
    msg.payload = rm;
    return msg;
}

const now = Date.now();

if (rm.state === 'COOLDOWN') {
    const cooldown_end = new Date(rm.cooldown_end_time).getTime();
    if (now >= cooldown_end) {
        // Cooldown elapsed during downtime — transition to DRY
        rm.state = 'DRY';
        rm.cooldown_end_time = null;
        flow.set('rain_monitor', rm, 'default');
    }
    // If cooldown hasn't elapsed, leave as COOLDOWN
    // Cooldown Poller will handle the transition when it fires
}

else if (rm.state === 'RAINING') {
    // We missed the rain stop event during restart
    // Check current Tempest state
    const observed = global.get('weather_canonical')?.observed || {};
    const config = global.get('config').landroid;
    const floor = config.rain_suppression.precipitation_floor_in_per_min;

    const still_raining = observed.precip_type !== 'None' 
        && (observed.precip_intensity / 60) >= floor;

    if (!still_raining) {
        // Rain stopped while we were down — transition to COOLDOWN
        rm.state = 'COOLDOWN';
        rm.last_rain_end = new Date().toISOString();

        const tiers = config.rain_accumulation_tiers;
        const acc = rm.event_accumulation;
        let skip_day = false;
        let cooldown_minutes = 30;

        for (const tier of tiers) {
            if (tier.max_inches === null || acc <= tier.max_inches) {
                if (tier.skip_day) {
                    skip_day = true;
                } else {
                    cooldown_minutes = tier.cooldown_minutes;
                }
                break;
            }
        }

        if (skip_day) {
            const [h, m] = config.schedule.earliest_start.split(':').map(Number);
            const tomorrow = new Date();
            tomorrow.setDate(tomorrow.getDate() + 1);
            tomorrow.setHours(h, m, 0, 0);
            rm.cooldown_end_time = tomorrow.toISOString();
        } else {
            rm.cooldown_end_time = new Date(now + cooldown_minutes * 60 * 1000).toISOString();
        }

        flow.set('rain_monitor', rm, 'default');
    }
    // If still raining, leave as RAINING — next observation will handle it
}

msg.payload = { ...rm, source: 'startup' };
return msg;

if (!msg.payload?.on || !msg.payload?.off) {
    return null;
}

const config = global.get('config').landroid.schedule;

const parseSchedexDate = (str) => new Date(str.replace(' GMT', '+00:00'));

let sunrise = parseSchedexDate(msg.payload.on);
let sunset = parseSchedexDate(msg.payload.off);

// If ran after sunrise, this will need to be moved back.
if (isTomorrow(sunrise)) {
    sunrise = backDate(sunrise);
}

// If ran after sunset, this will need to be moved back.
if (isTomorrow(sunset)) {
    sunset = backDate(sunset);
}

let window_start = new Date(sunrise.getTime() + config.sunrise_buffer_minutes * 60000);
let window_end = new Date(sunset.getTime() - config.sunset_buffer_minutes * 60000);

flow.set('window_start', window_start.toISOString());
flow.set('window_end', window_end.toISOString());

node.status({ 
    fill: 'green', 
    shape: 'dot', 
    text: `${window_start.toLocaleTimeString()} → ${window_end.toLocaleTimeString()}`
});

node.log(`Solar window: ${window_start.toISOString()} to ${window_end.toISOString()}`);

const fmt = (d) => d.toLocaleTimeString('en-US', { 
    hour: 'numeric', 
    minute: '2-digit', 
    hour12: true,
    timeZone: global.get('config').location.timezone
});

msg.topic = 'highland/state/landroid/session';
msg.payload = JSON.stringify({ mowing_window: `${fmt(window_start)} - ${fmt(window_end)}` });
msg.retain = true;
node.send(msg);

return null;

function backDate(date) {
    date.setHours(date.getHours() - 24);
    return date;
}

function isTomorrow(date) {
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);

  return date.getDate() === tomorrow.getDate() &&
         date.getMonth() === tomorrow.getMonth() &&
         date.getFullYear() === tomorrow.getFullYear();
}

const voltage = parseFloat(msg.payload);
if (isNaN(voltage)) return null;

let sm = flow.get('session_manager', 'default') || {};
const prev_voltage = sm.voltage_prev || null;
const prev_trend = sm.voltage_trend || null;
const mower_state = msg.data?.new_state?.attributes?.state
    || flow.get('mower_state') || null;

// Update trend if we have a previous reading
let new_trend = prev_trend;
if (prev_voltage !== null) {
    const delta = voltage - prev_voltage;
    if (Math.abs(delta) >= 0.05) { // ignore noise
        const direction = delta > 0 ? 'charging' : 'discharging';
        if (direction !== prev_trend) {
            new_trend = direction;
        }
    }
}

// Update context
sm.voltage_prev = voltage;
sm.voltage_trend = new_trend;
flow.set('session_manager', sm, 'default');

node.status({
    fill: new_trend === 'charging' ? 'green' : new_trend === 'discharging' ? 'yellow' : 'grey',
    shape: 'dot',
    text: `${voltage}V ${new_trend || 'unknown'}`
});

// Only emit to FSM when we detect rising→falling while docked
// This is the charge peak signal
const mower_docked = mower_state === 'docked';
const peak_detected = prev_trend === 'charging' && new_trend === 'discharging' && mower_docked;

if (new_trend !== null) {
    node.send({
        topic: "highland/state/landroid/battery_charge_state",
        payload: new_trend === 'charging' ? 'Charging' : 'Discharging',
        retain: true });
}

if (peak_detected) {
    node.send({
        topic: "highland/event/landroid/charge_peak",
        payload: JSON.stringify({ timestamp: new Date().toISOString(), voltage }),
        retain: false });
}

return null;

const state = msg.payload;
const prev_state = msg.data?.old_state?.state || null;
flow.set('mower_state', state);

node.status({ fill: 'blue', shape: 'dot', text: state });

msg.payload = {
    type: 'mower_state',
    state,
    previous: prev_state
};

// Force discharging immediately when leaving dock
const charge_override = (prev_state === 'docked' && state !== 'docked')
    ? { topic: 'highland/state/landroid/battery_charge_state', payload: 'Discharging', retain: true }
    : null;

return [msg, charge_override];

const error = msg.payload;

node.status({ fill: error === 'no_error' ? 'grey' : 'red', shape: 'dot', text: error });

msg.payload = {
    type: 'mower_error',
    error,
    previous: msg.data?.old_state?.state || null
};

return msg;

const data = msg.payload;
msg.payload = {
    type: 'charge_peak',
    timestamp: data.timestamp,
    voltage: data.voltage
};
return msg;

const config = global.get('config').landroid;
const now = new Date();

const defaults = {
    state: 'WAITING',
    session_phase: 'MOWING',
    battery_low_pending: false,
    error_during_session: false,
    edge_cut_pending: false,
    awaiting_charge_peak: false,
    conditions_validated: false,
    we_sent_dock: false
};

let sm = Object.assign({}, defaults, flow.get('session_manager', 'default') || {});

const { type } = msg.payload;

const window_start = new Date(flow.get('window_start'));
const window_end = new Date(flow.get('window_end'));

// Time gate helpers
const timeForEdgeCut = () => now <= new Date(window_end.getTime() - config.schedule.min_edge_cut_window_minutes * 60000);
const timeForMow = () => now <= new Date(window_end.getTime() - config.schedule.min_mow_window_minutes * 60000);

// Conditions check — simplified if conditions already validated today
const conditionsOk = (p) => sm.conditions_validated
    ? p.temp_ok && p.mow_ready
    : p.conditions_met;

node.status({ fill: 'grey', shape: 'dot', text: `${sm.state} | ${sm.session_phase}` });

// ── WINDOW OPEN ──────────────────────────────────────────
if (type === 'window_open') {
    if (sm.state !== 'WAITING' && sm.state !== 'DONE') return null;
    // Treat same as a conditions_check arriving in WAITING
    // Re-evaluate via next conditions_check — just ensure we're in WAITING
    sm.state = 'WAITING';
    flow.set('session_manager', sm, 'default');
    node.status({ fill: 'grey', shape: 'dot', text: 'WAITING | window opened' });
    return null;
}

// ── WINDOW CLOSE ─────────────────────────────────────────
if (type === 'window_close') {
    const mower_state = flow.get('mower_state') || 'docked';
    const needs_dock = mower_state === 'mowing' || mower_state === 'edge_cut' || mower_state === 'starting';

    sm.battery_low_pending = false;
    sm.error_during_session = false;
    sm.awaiting_charge_peak = false;
    sm.conditions_validated = false;
    sm.we_sent_dock = needs_dock;
    sm.state = 'DONE';
    flow.set('session_manager', sm, 'default');
    node.status({ fill: 'grey', shape: 'dot', text: 'DONE | window closed' });

    if (needs_dock) {
        msg.payload = { command: 'dock', reason: 'window_close' };
        return msg;
    }
    return null;
}

// ── SAFETY RECALL ──────────────────────────────────────────────────────
if (type === 'safety_dock') {
    const mower_state = flow.get('mower_state') || 'docked';
    const needs_dock = mower_state === 'mowing' || mower_state === 'edge_cut' || mower_state === 'starting';
    sm.state = 'DONE';
    sm.conditions_validated = false;
    flow.set('session_manager', sm, 'default');
    node.status({ fill: 'grey', shape: 'dot', text: 'DONE | safety net' });
    if (needs_dock) {
        sm.we_sent_dock = true;
        msg.payload = { command: 'dock', reason: 'safety_net' };
        return msg;
    }
    return null;
}

// ── STARTING OUTSIDE WINDOW GUARD ────────────────────────
if (type === 'mower_state' && msg.payload.state === 'starting') {
    const in_window = now >= window_start && now <= window_end;
    if (!in_window) {
        sm.we_sent_dock = true;
        flow.set('session_manager', sm, 'default');
        node.status({ fill: 'orange', shape: 'dot', text: `${sm.state} | outside window dock` });
        msg.payload = { command: 'dock', reason: 'outside_window' };
        return msg;
    }
}

// ── PARTY MODE ───────────────────────────────────────────
if (type === 'party_mode') {
    const enabled = msg.payload.enabled;
    sm.party_mode_active = enabled;

    if (enabled) {
        const needs_dock = sm.state === 'MOWING' || sm.state === 'EDGE_CUTTING';
        if (needs_dock) sm.we_sent_dock = true;
        sm.state = 'PAUSED';
        flow.set('session_manager', sm, 'default');
        node.status({ fill: 'grey', shape: 'dot', text: 'PAUSED | party mode' });
        if (needs_dock) {
            msg.payload = { command: 'dock', reason: 'party_mode' };
            return msg;
        }
        return null;
    }

    // Party mode turned off
    if (sm.state !== 'PAUSED') {
        flow.set('session_manager', sm, 'default');
        return null;
    }

    sm.we_sent_dock = false;
    const in_window = now >= window_start && now <= window_end;
    if (!in_window) {
        sm.state = 'DONE';
        flow.set('session_manager', sm, 'default');
        node.status({ fill: 'grey', shape: 'dot', text: 'DONE | window passed' });
        return null;
    }

    sm.state = 'WAITING';
    flow.set('session_manager', sm, 'default');
    node.status({ fill: 'grey', shape: 'dot', text: 'WAITING | party mode off' });
    return null;
}

// ── WAITING ──────────────────────────────────────────────
if (sm.state === 'WAITING') {
    if (type !== 'conditions_check') return null;

    const ok = conditionsOk(msg.payload);

    if (!ok) {
        sm.state = 'CONDITIONS_WAIT';
        flow.set('session_manager', sm, 'default');
        node.status({ fill: 'yellow', shape: 'dot', text: 'CONDITIONS_WAIT' });
        return null;
    }

    // Conditions good — start session
    const command = sm.edge_cut_pending ? 'ots_edge_cut' : 'start_mowing';
    if (command === 'ots_edge_cut') {
        sm.session_phase = 'EDGE_CUT';
        sm.edge_cut_pending = false;
    } else {
        sm.session_phase = 'MOWING';
    }
    sm.state = 'MOWING';
    sm.conditions_validated = true;
    flow.set('session_manager', sm, 'default');

    msg.payload = { command };
    return msg;
}

// ── CONDITIONS_WAIT ──────────────────────────────────────
if (sm.state === 'CONDITIONS_WAIT') {
    if (type !== 'conditions_check') return null;

    if (!conditionsOk(msg.payload)) return null;

    const command = sm.edge_cut_pending ? 'ots_edge_cut' : 'start_mowing';
    if (command === 'ots_edge_cut') {
        sm.session_phase = 'EDGE_CUT';
        sm.edge_cut_pending = false;
    } else {
        sm.session_phase = 'MOWING';
    }
    sm.state = 'MOWING';
    sm.conditions_validated = true;
    flow.set('session_manager', sm, 'default');

    msg.payload = { command };
    return msg;
}

// ── MOWING ───────────────────────────────────────────────
if (sm.state === 'MOWING') {

    if (type === 'mower_error') {
        const error = msg.payload.error;
        if (error === 'battery_low') {
            sm.battery_low_pending = true;
        } else if (error === 'no_error') {
            sm.battery_low_pending = false;
            sm.error_during_session = false;
        } else {
            sm.error_during_session = true;
        }
        flow.set('session_manager', sm, 'default');
        return null;
    }

    if (type === 'mower_state') {
        const state = msg.payload.state;

        if (state === 'returning' && !sm.battery_low_pending && !sm.we_sent_dock) {
            // Natural completion dock detected
            sm.awaiting_charge_peak = true;
            sm.state = 'CHARGE_WAIT';
            flow.set('session_manager', sm, 'default');
            node.status({ fill: 'blue', shape: 'dot', text: `CHARGE_WAIT | ${sm.session_phase}` });
            return null;
        }

        if (state === 'returning' && sm.battery_low_pending) {
            // Battery recharge mid-session — Mowen handles autonomously
            flow.set('session_manager', sm, 'default');
            return null;
        }
    }

    if (type === 'rain') {
        sm.we_sent_dock = true;
        sm.state = 'COOLDOWN';
        flow.set('session_manager', sm, 'default');
        node.status({ fill: 'red', shape: 'dot', text: `COOLDOWN | ${sm.session_phase}` });
        msg.payload = { command: 'dock', reason: 'rain' };
        return msg;
    }

    if (type === 'conditions_check') return null; // ignore during active session

    return null;
}

// ── EDGE_CUTTING ─────────────────────────────────────────
if (sm.state === 'EDGE_CUTTING') {

    if (type === 'mower_error') {
        const error = msg.payload.error;
        if (error === 'battery_low') {
            sm.battery_low_pending = true;
        } else if (error === 'no_error') {
            sm.battery_low_pending = false;
        } else {
            sm.error_during_session = true;
        }
        flow.set('session_manager', sm, 'default');
        return null;
