    if (type === 'conditions_check') return null;

    return null;
}

// ── CHARGE_WAIT ──────────────────────────────────────────
if (sm.state === 'CHARGE_WAIT') {
    if (type === 'conditions_check') return null;

    if (type === 'mower_state') {
        const state = msg.payload.state;
        if (state === 'mowing' || state === 'starting') {
            sm.state = 'MOWING';
            sm.awaiting_charge_peak = false;
            sm.we_sent_dock = false;
            flow.set('session_manager', sm, 'default');
            node.status({ fill: 'green', shape: 'dot', text: 'MOWING | resumed' });
            return null;
        }
        if (state === 'edge_cut') {
            sm.state = 'EDGE_CUTTING';
            sm.awaiting_charge_peak = false;
            sm.we_sent_dock = false;
            flow.set('session_manager', sm, 'default');
            node.status({ fill: 'green', shape: 'dot', text: 'EDGE_CUTTING | resumed' });
            return null;
        }
    }

    if (type === 'rain') {
        // Already docked — no dock command needed, just move to COOLDOWN
        sm.state = 'COOLDOWN';
        flow.set('session_manager', sm, 'default');
        node.status({ fill: 'red', shape: 'dot', text: `COOLDOWN | ${sm.session_phase}` });
        return null;
    }

    if (type === 'charge_peak') {
        sm.awaiting_charge_peak = false;
        sm.we_sent_dock = false;

        const mow_ready = flow.get('mow_ready');
        const observed = flow.get('latest_observation') || {};
        const temp_ok = (observed.temperature || 0) >= config.mow_conditions.min_temp_f;

        if (!mow_ready || !temp_ok) {
            // Conditions not suitable — wait in CHARGE_WAIT for conditions to improve
            flow.set('session_manager', sm, 'default');
            node.status({ fill: 'yellow', shape: 'dot', text: `CHARGE_WAIT waiting | ${sm.session_phase}` });
            return null;
        }

        if (sm.session_phase === 'MOWING') {
            const edge_cut_enabled = config.schedule.edge_cut_enabled !== false;
            if (edge_cut_enabled && timeForEdgeCut()) {
                sm.session_phase = 'EDGE_CUT';
                sm.state = 'EDGE_CUTTING';
                flow.set('session_manager', sm, 'default');
                node.status({ fill: 'green', shape: 'dot', text: 'EDGE_CUTTING' });
                msg.payload = { command: 'ots_edge_cut' };
                return msg;
            } else {
                // Edge cut disabled or no time — go straight to mowing if time permits
                sm.session_phase = 'MOWING';
                if (timeForMow()) {
                    sm.state = 'MOWING';
                    flow.set('session_manager', sm, 'default');
                    node.status({ fill: 'green', shape: 'dot', text: 'MOWING' });
                    msg.payload = { command: 'start_mowing' };
                    return msg;
                } else {
                    sm.edge_cut_pending = true;
                    sm.state = 'DONE';
                    flow.set('session_manager', sm, 'default');
                    node.status({ fill: 'grey', shape: 'dot', text: 'DONE' });
                    return null;
                }
            }
        }

        if (sm.session_phase === 'EDGE_CUT') {
            sm.session_phase = 'MOWING';
            if (timeForMow()) {
                sm.state = 'MOWING';
                flow.set('session_manager', sm, 'default');
                node.status({ fill: 'green', shape: 'dot', text: 'MOWING' });
                msg.payload = { command: 'start_mowing' };
                return msg;
            } else {
                sm.state = 'DONE';
                flow.set('session_manager', sm, 'default');
                node.status({ fill: 'grey', shape: 'dot', text: 'DONE' });
                return null;
            }
        }
    }

    return null;
}

// ── COOLDOWN ─────────────────────────────────────────────
if (sm.state === 'COOLDOWN') {
    if (type === 'mower_state') {
        const state = msg.payload.state;
        if (state === 'mowing' || state === 'starting') {
            sm.state = 'MOWING';
            sm.we_sent_dock = false;
            flow.set('session_manager', sm, 'default');
            node.status({ fill: 'green', shape: 'dot', text: 'MOWING | manual start' });
            return null;
        }
    }

    if (type !== 'conditions_check') return null;  

    const p = msg.payload;
    if (!p.conditions_met) return null;
    if (now > new Date(window_end.getTime() - config.rain_suppression.resume_cutoff_minutes * 60000)) {
        sm.state = 'DONE';
        flow.set('session_manager', sm, 'default');
        node.status({ fill: 'grey', shape: 'dot', text: 'DONE' });
        return null;
    }

    // Resume — edge cut takes priority if pending
    sm.we_sent_dock = false;
    const command = sm.edge_cut_pending ? 'ots_edge_cut' : 'start_mowing';
    if (command === 'ots_edge_cut') {
        sm.session_phase = 'EDGE_CUT';
        sm.edge_cut_pending = false;
        sm.state = 'EDGE_CUTTING';
    } else {
        sm.state = 'MOWING';
    }
    flow.set('session_manager', sm, 'default');
    node.status({ fill: 'green', shape: 'dot', text: `${sm.state} | ${sm.session_phase}` });
    msg.payload = { command };
    return msg;
}

// ── DONE ─────────────────────────────────────────────────
if (sm.state === 'DONE') {
    if (type !== 'conditions_check') return null;

    // New day starts when we receive a conditions_check within the new window
    if (now >= window_start && now <= window_end) {
        sm.state = 'WAITING';
        sm.battery_low_pending = false;
        sm.error_during_session = false;
        sm.awaiting_charge_peak = false;
        sm.conditions_validated = false;
        sm.we_sent_dock = false;
        flow.set('session_manager', sm, 'default');
        node.status({ fill: 'grey', shape: 'dot', text: 'WAITING | reset' });
    }
    return null;
}

