const now = new Date();
const window_start = new Date(flow.get('window_start'));
const window_end = new Date(flow.get('window_end'));
const mow_ready = flow.get('mow_ready');
const config = global.get('config').landroid;

// Outside solar window — nothing to evaluate
if (now < window_start || now > window_end) {
    node.status({ fill: 'grey', shape: 'dot', text: 'outside window' });
    return null;
}

// Check temperature and dew point
const observed = flow.get('latest_observation') || {};
const temp = observed.temperature;
const humidity = observed.humidity;

if (temp === undefined || humidity === undefined) {
    node.status({ fill: 'yellow', shape: 'dot', text: 'no weather data' });
    return null;
}

const dew_point = temp - ((100 - humidity) / 5);
const temp_ok = temp >= config.mow_conditions.min_temp_f;
const solar_radiation = observed.solar_radiation || 0;
const solar_ok = solar_radiation >= config.mow_conditions.min_solar_radiation_wm2;
const dew_ok = (temp - dew_point) >= config.mow_conditions.dew_point_spread_threshold_f || solar_ok;
const conditions_met = temp_ok && dew_ok && mow_ready;

node.status({
    fill: conditions_met ? 'green' : 'yellow',
    shape: 'dot',
    text: `${temp.toFixed(1)}°F sp:${(temp-dew_point).toFixed(1)} sol:${solar_radiation} ${mow_ready ? 'clear' : 'rain'}`
});

const sm = flow.get('session_manager', 'default') || {};
const conditions_validated = sm.conditions_validated || false;

// conditions_delay_active reflects FSM logic:
// after first start, only temperature still gates (dew/solar already validated)
let conditions_delay_active;
let conditions_status;

if (conditions_validated) {
    conditions_delay_active = !temp_ok;
    conditions_status = temp_ok ? 'Ready' : 'Temperature';
} else {
    conditions_delay_active = !temp_ok || !dew_ok;
    if (!temp_ok && !dew_ok)  conditions_status = 'Temperature + Humidity';
    else if (!temp_ok)         conditions_status = 'Temperature';
    else if (!dew_ok)          conditions_status = 'Humidity';
    else                       conditions_status = 'Ready';
}

// Publish conditions state to MQTT
node.send([
    {
        payload: {
            type: 'conditions_check',
            conditions_met,
            conditions_validated,
            temp,
            dew_point,
            temp_ok,
            dew_ok,
            solar_ok,
            mow_ready: mow_ready || false
        }
    },
    {
        topic: 'highland/state/landroid/conditions',
        payload: JSON.stringify({ conditions_delay_active, conditions_status }),
        retain: true
    }
]);

return null;

