const now = new Date();
const window_start = new Date(flow.get('window_start'));
const window_end = new Date(flow.get('window_end'));

const was_in_window = flow.get('scheduler_in_window') || false;
const in_window = now >= window_start && now <= window_end;

const safety_minutes = config.rain_suppression.end_of_day_safety_minutes;
const safety_end = new Date(window_end.getTime() + safety_minutes * 60000);
const mower_state = flow.get('mower_state') || 'docked';

if (now > window_end && now <= safety_end && (mower_state === 'mowing' || mower_state === 'edge_cut' || mower_state === 'starting')) {
    msg.payload = { type: 'safety_dock' };
    node.status({ fill: 'orange', shape: 'dot', text: 'safety net firing' });
    return msg;
}

// Detect crossings
if (!was_in_window && in_window) {
    flow.set('scheduler_in_window', true);
    msg.payload = { type: 'window_open' };
    return msg;
}

if (was_in_window && !in_window) {
    flow.set('scheduler_in_window', false);
    msg.payload = { type: 'window_close' };
    return msg;
}

// No crossing — update state and emit nothing
flow.set('scheduler_in_window', in_window);
return null;

const mow_ready = msg.payload.mow_ready;
const prev_mow_ready = flow.get('prev_mow_ready', 'volatile');
const flow_mow_ready = flow.get('mow_ready');  // authoritative flow context value
const mower_state = flow.get('mower_state') || 'docked';

flow.set('prev_mow_ready', mow_ready, 'volatile');

// Both MQTT payload AND flow context must agree mow_ready is false
if (prev_mow_ready === true && mow_ready === false && flow_mow_ready === false &&
    (mower_state === 'mowing' || mower_state === 'edge_cut')) {
    msg.payload = { type: 'rain' };
    return msg;
}

return null;

const state = msg.payload;

msg.payload = {
    type: 'party_mode',
    enabled: state === "on"
};

node.status({fill:"grey",shape:"ring",text: state});

